BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?constraint ?constraintName ?constrainedElement WHERE {
  ?constraint rdf:type vocab:duration%20constraint .
  ?constraint vocab:NamedElement_name ?constraintName .
  OPTIONAL { ?constraint vocab:Constraint_constrainedElement ?constrainedElement }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?scenario ?scenarioName ?owner ?ownerName WHERE {
  ?scenario rdf:type vocab:instance%20specification .
  ?scenario vocab:NamedElement_name ?scenarioName .
  FILTER(CONTAINS(LCASE(STR(?scenarioName)), LCASE("Duration Scenario")))
  OPTIONAL {
    ?scenario vocab:Element_owner ?owner .
    ?owner vocab:NamedElement_name ?ownerName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?constraint ?constraintName ?spec WHERE {
  ?constraint rdf:type vocab:time%20constraint .
  ?constraint vocab:NamedElement_name ?constraintName .
  OPTIONAL { ?constraint vocab:Constraint_specification ?spec }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?constraintName ?spec WHERE {
  ?constraint rdf:type <http://api.koneksys.com/cameo/vocab/duration%20constraint> .
  ?constraint <http://api.koneksys.com/cameo/vocab/NamedElement_name> ?constraintName .
  OPTIONAL { ?constraint <http://api.koneksys.com/cameo/vocab/Constraint_specification> ?spec }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?scenarioBase WHERE {
  {
    SELECT ?name WHERE {
      ?s <http://api.koneksys.com/cameo/vocab/NamedElement_name> ?name .
      ?s rdf:type ?type .
      FILTER(CONTAINS(?name, "Duration Scenario"))
    }
  }
  BIND(STRBEFORE(?name, ".aps") as ?base1)
  BIND(STRBEFORE(?name, ".analysis") as ?base2)  
  BIND(STRBEFORE(?name, "%20at%20") as ?base3)
  BIND(COALESCE(?base1, ?base2, ?base3, ?name) as ?scenarioBase)
}
ORDER BY ?scenarioBase

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?s ?name ?ownedElem ?ownedName WHERE {
  ?s <http://api.koneksys.com/cameo/vocab/NamedElement_name> ?name .
  ?s rdf:type <http://api.koneksys.com/cameo/vocab/test%20case> .
  FILTER(CONTAINS(?name, "Duration Scenario"))
  OPTIONAL {
    ?s <http://api.koneksys.com/cameo/vocab/Element_ownedElement> ?ownedElem .
    ?ownedElem <http://api.koneksys.com/cameo/vocab/NamedElement_name> ?ownedName .
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?s ?name ?owner ?ownerName WHERE {
  ?s <http://api.koneksys.com/cameo/vocab/NamedElement_name> ?name .
  ?s rdf:type <http://api.koneksys.com/cameo/vocab/test%20case> .
  FILTER(CONTAINS(?name, "Duration Scenario"))
  OPTIONAL {
    ?s <http://api.koneksys.com/cameo/vocab/Element_owner> ?owner .
    ?owner <http://api.koneksys.com/cameo/vocab/NamedElement_name> ?ownerName .
  }
}
LIMIT 50
